const s   = $('Set · Settings').first().json;
const b   = $('Webhook · Onboard').first().json.body;
const row = $input.first().json;
const clientId = row.Id || row.id || row.ncRecordId;
const slug = ('c-' + b.chatwoot_inbox_id + '-' + clientId).replace(/[^a-zA-Z0-9_-]/g,'');

// Per-client webhook workflow — thin wrapper that just injects client_id then calls
// the one shared engine directly by workflow id. No industry-routing layer: every
// client runs the same engine, which already reads client.industry from NocoDB at
// runtime for any industry-specific behavior it needs.
const wrapper = {
  name: 'Bot · ' + (b.client_name || ('client-'+clientId)) + ' (#' + clientId + ')',
  nodes: [
    { parameters:{ httpMethod:'POST', path: slug, responseMode:'responseNode', options:{} },
      name:'Webhook', type:'n8n-nodes-base.webhook', typeVersion:2, position:[0,0], webhookId: slug },
    { parameters:{ respondWith:'json', responseBody:'={ "ok": true }', options:{} },
      name:'Respond ACK', type:'n8n-nodes-base.respondToWebhook', typeVersion:1.1, position:[0,200] },
    { parameters:{ assignments:{ assignments:[ { id:'cid', name:'client_id', value:String(clientId), type:'string' } ] }, includeOtherFields:true, options:{} },
      name:'Set client_id', type:'n8n-nodes-base.set', typeVersion:3.4, position:[260,0] },
    { parameters:{ workflowId:{ __rl:true, value: s.engine_workflow_id, mode:'id' }, options:{} },
      name:'Run engine', type:'n8n-nodes-base.executeWorkflow', typeVersion:1.2, position:[520,0] }
  ],
  connections: {
    'Webhook':     { main: [ [ { node:'Respond ACK', type:'main', index:0 }, { node:'Set client_id', type:'main', index:0 } ] ] },
    'Set client_id': { main: [ [ { node:'Run engine', type:'main', index:0 } ] ] }
  },
  settings: { executionOrder:'v1' }
};

const webhook_url = s.n8n_base.replace(/\/$/,'') + '/webhook/' + slug;
return [{ json: { wrapper, webhook_url, clientId } }];
